import java.io.*;
import java.util.*;

public class Main {
    private static void swap(int[] a,int i,int j){int t=a[i];a[i]=a[j];a[j]=t;}
    private static int partition(int[] a,int low,int high){int pivot=a[high];int i=low-1;for(int j=low;j<high;++j){if(a[j]<pivot){i++;swap(a,i,j);}}swap(a,i+1,high);return i+1;}
    private static void quickSort(int[] a,int low,int high){if(low<high){int pi=partition(a,low,high);quickSort(a,low,pi-1);quickSort(a,pi+1,high);}}
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder sb=new StringBuilder();
        while(T-- > 0){
            int N=Integer.parseInt(br.readLine().trim());
            int[] arr=new int[N];
            st=new StringTokenizer(br.readLine());
            for(int i=0;i<N;++i) arr[i]=Integer.parseInt(st.nextToken());
            quickSort(arr,0,N-1);
            for(int i=0;i<N;++i){
                sb.append(arr[i]);
                if(i+1<N) sb.append(' ');
            }
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

